              const text = document.body.innerText;
              const rowsMatch =
                rows.length === expectedRows.length &&
                expectedRows.every((row, index) => rows[index] === row);

              if (!rowsMatch || (expectedRows.length === 0 && !noResultsVisible)) {
                return false;
              }

              return {
                links,
                noResultsVisible,
                rows,
                text,
              };
